import React from 'react';
import {
  Card,
  CardContent,
  Typography,
  Box,
  Chip,
  LinearProgress,
  Button,
  Avatar,
  IconButton,
  Menu,
  MenuItem,
  ListItemIcon,
  ListItemText,
  Divider,
} from '@mui/material';
import {
  Assignment,
  Schedule,
  Grade,
  AttachFile,
  MoreVert,
  Edit,
  Delete,
  Share,
  Visibility,
  Download,
} from '@mui/icons-material';
import { Assignment as AssignmentType, User } from '../../types';

interface AssignmentCardProps {
  assignment: AssignmentType;
  currentUser: User;
  onView?: (assignmentId: string) => void;
  onEdit?: (assignmentId: string) => void;
  onDelete?: (assignmentId: string) => void;
  onSubmit?: (assignmentId: string) => void;
}

const AssignmentCard: React.FC<AssignmentCardProps> = ({
  assignment,
  currentUser,
  onView,
  onEdit,
  onDelete,
  onSubmit,
}) => {
  const [anchorEl, setAnchorEl] = React.useState<null | HTMLElement>(null);

  const handleMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const getTimeRemaining = () => {
    const now = new Date();
    const dueDate = new Date(assignment.dueDate);
    const diff = dueDate.getTime() - now.getTime();
    
    if (diff <= 0) return 'Overdue';
    
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
    
    if (days > 0) return `${days} day${days > 1 ? 's' : ''} left`;
    if (hours > 0) return `${hours} hour${hours > 1 ? 's' : ''} left`;
    return 'Due soon';
  };

  const getPriorityColor = () => {
    const now = new Date();
    const dueDate = new Date(assignment.dueDate);
    const diff = dueDate.getTime() - now.getTime();
    const days = diff / (1000 * 60 * 60 * 24);
    
    if (days < 0) return 'error';
    if (days < 1) return 'warning';
    if (days < 3) return 'info';
    return 'success';
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'quiz': return '📝';
      case 'exam': return '📋';
      case 'project': return '🛠️';
      default: return '📄';
    }
  };

  const isOverdue = new Date(assignment.dueDate) < new Date();
  const isStudent = currentUser.role === 'student';

  return (
    <Card
      sx={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        transition: 'transform 0.2s ease-in-out, box-shadow 0.2s ease-in-out',
        '&:hover': {
          transform: 'translateY(-2px)',
          boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
        },
        border: isOverdue ? '1px solid #f44336' : '1px solid transparent',
      }}
    >
      <CardContent sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 2 }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Typography variant="h6" component="h3" sx={{ fontWeight: 600 }}>
              {assignment.title}
            </Typography>
            <Chip
              label={assignment.type}
              size="small"
              color={getPriorityColor() as any}
              variant="outlined"
            />
          </Box>
          <IconButton onClick={handleMenuOpen} size="small">
            <MoreVert />
          </IconButton>
        </Box>

        {/* Course Info */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
          <Avatar sx={{ width: 24, height: 24, bgcolor: 'primary.light' }}>
            <Assignment fontSize="small" />
          </Avatar>
          <Typography variant="body2" color="text.secondary">
            {assignment.course.title} ({assignment.course.code})
          </Typography>
        </Box>

        {/* Description */}
        <Typography
          variant="body2"
          color="text.secondary"
          sx={{
            mb: 2,
            display: '-webkit-box',
            WebkitLineClamp: 2,
            WebkitBoxOrient: 'vertical',
            overflow: 'hidden',
          }}
        >
          {assignment.description}
        </Typography>

        {/* Due Date and Time */}
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
          <Schedule fontSize="small" color="action" />
          <Typography variant="body2" color="text.secondary">
            Due: {formatDate(assignment.dueDate)}
          </Typography>
          <Chip
            label={getTimeRemaining()}
            size="small"
            color={isOverdue ? 'error' : getPriorityColor() as any}
            variant="outlined"
          />
        </Box>

        {/* Points and Attachments */}
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Grade fontSize="small" color="action" />
            <Typography variant="body2" color="text.secondary">
              {assignment.maxPoints} points
            </Typography>
          </Box>
          {assignment.attachments && assignment.attachments.length > 0 && (
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
              <AttachFile fontSize="small" color="action" />
              <Typography variant="body2" color="text.secondary">
                {assignment.attachments.length} file{assignment.attachments.length > 1 ? 's' : ''}
              </Typography>
            </Box>
          )}
        </Box>

        {/* Progress Bar (for students) */}
        {isStudent && (
          <Box sx={{ mb: 2 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1 }}>
              <Typography variant="body2" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="body2" color="text.secondary">
                0% Complete
              </Typography>
            </Box>
            <LinearProgress variant="determinate" value={0} sx={{ height: 6, borderRadius: 3 }} />
          </Box>
        )}

        {/* Actions */}
        <Box sx={{ display: 'flex', gap: 1, mt: 'auto' }}>
          <Button
            variant="contained"
            startIcon={<Visibility />}
            onClick={() => onView?.(assignment.id)}
            sx={{ flexGrow: 1 }}
          >
            {isStudent ? 'View Assignment' : 'View Details'}
          </Button>
          {isStudent && !isOverdue && (
            <Button
              variant="outlined"
              onClick={() => onSubmit?.(assignment.id)}
            >
              Submit
            </Button>
          )}
        </Box>
      </CardContent>

      {/* Actions Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
      >
        <MenuItem onClick={() => { onView?.(assignment.id); handleMenuClose(); }}>
          <ListItemIcon>
            <Visibility fontSize="small" />
          </ListItemIcon>
          <ListItemText>View Details</ListItemText>
        </MenuItem>
        {currentUser.role !== 'student' && (
          <MenuItem onClick={() => { onEdit?.(assignment.id); handleMenuClose(); }}>
            <ListItemIcon>
              <Edit fontSize="small" />
            </ListItemIcon>
            <ListItemText>Edit Assignment</ListItemText>
          </MenuItem>
        )}
        <MenuItem>
          <ListItemIcon>
            <Share fontSize="small" />
          </ListItemIcon>
          <ListItemText>Share</ListItemText>
        </MenuItem>
        {assignment.attachments && assignment.attachments.length > 0 && (
          <MenuItem>
            <ListItemIcon>
              <Download fontSize="small" />
            </ListItemIcon>
            <ListItemText>Download Files</ListItemText>
          </MenuItem>
        )}
        {currentUser.role !== 'student' && (
          <>
            <Divider />
            <MenuItem onClick={() => { onDelete?.(assignment.id); handleMenuClose(); }} sx={{ color: 'error.main' }}>
              <ListItemIcon>
                <Delete fontSize="small" color="error" />
              </ListItemIcon>
              <ListItemText>Delete Assignment</ListItemText>
            </MenuItem>
          </>
        )}
      </Menu>
    </Card>
  );
};

export default AssignmentCard;
